// pages/Progress.jsx — Progress tracker with stats, topic list, quiz history
import React, { useState } from "react";
import { Link } from "react-router-dom";
import { TOPICS } from "../data/topicsData";
import { getCompletedTopics, getQuizScores, clearProgress } from "../utils/progress";

function StatCard({ value, label, sublabel, color = "#6366f1" }) {
  return (
    <div
      className="glass p-5 text-center"
      style={{ border: `1px solid ${color}20` }}
    >
      <p
        className="text-3xl font-bold mb-0.5"
        style={{ color, textShadow: `0 0 16px ${color}40` }}
      >
        {value}
      </p>
      <p className="text-sm text-slate-300 font-medium">{label}</p>
      {sublabel && <p className="text-xs text-slate-500 mt-0.5">{sublabel}</p>}
    </div>
  );
}

export default function Progress() {
  const [completed, setCompleted] = useState(getCompletedTopics());
  const [quizScores, setQuizScores] = useState(getQuizScores());

  const handleClear = () => {
    if (window.confirm("Clear all progress data? This cannot be undone.")) {
      clearProgress();
      setCompleted([]);
      setQuizScores([]);
    }
  };

  const pctDone = Math.round((completed.length / TOPICS.length) * 100);
  const avgScore =
    quizScores.length > 0
      ? Math.round(
          quizScores.reduce((sum, s) => sum + (s.score / s.total) * 100, 0) /
            quizScores.length
        )
      : null;

  return (
    <main className="max-w-3xl mx-auto px-5 py-10">
      {/* Header */}
      <div className="mb-8 animate-fade-up">
        <span className="section-label glow-dot">Your Progress</span>
        <h1 className="text-2xl font-bold text-white mt-2 mb-1" style={{ letterSpacing: "-0.01em" }}>
          Learning Dashboard
        </h1>
        <p className="text-slate-400 text-sm">Track your activity across all AptiPrep topics.</p>
      </div>

      {/* Stat cards */}
      <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 mb-6 animate-fade-up-d1">
        <StatCard
          value={`${completed.length}/${TOPICS.length}`}
          label="Topics Viewed"
          sublabel={`${pctDone}% complete`}
          color="#6366f1"
        />
        <StatCard
          value={quizScores.length}
          label="Quizzes Taken"
          color="#38bdf8"
        />
        {avgScore !== null && (
          <StatCard
            value={`${avgScore}%`}
            label="Avg Score"
            sublabel="across all quizzes"
            color={avgScore >= 70 ? "#22c55e" : avgScore >= 50 ? "#f59e0b" : "#ef4444"}
          />
        )}
      </div>

      {/* Progress bar */}
      <div className="glass p-4 mb-6 animate-fade-up-d2">
        <div className="flex items-center justify-between mb-2">
          <span className="section-label">Overall Progress</span>
          <span className="text-xs font-mono" style={{ color: "#6366f1" }}>{pctDone}%</span>
        </div>
        <div className="progress-track">
          <div className="progress-fill" style={{ width: `${pctDone}%` }} />
        </div>
      </div>

      {/* Completed topics */}
      <section className="glass mb-5 overflow-hidden animate-fade-up-d3">
        <div
          className="flex items-center justify-between px-5 py-3.5"
          style={{ borderBottom: "1px solid rgba(255,255,255,0.06)" }}
        >
          <p className="section-label">Topics Viewed</p>
          <span className="text-xs font-mono" style={{ color: "#475569" }}>
            {completed.length}/{TOPICS.length}
          </span>
        </div>

        {completed.length === 0 ? (
          <div className="px-5 py-8 text-center">
            <p className="text-slate-500 text-sm mb-3">No topics viewed yet.</p>
            <Link to="/" className="btn-primary text-xs" style={{ padding: "8px 16px", display: "inline-block" }}>
              Start Learning →
            </Link>
          </div>
        ) : (
          <ul className="list-none m-0 p-0">
            {TOPICS.filter((t) => completed.includes(t.slug)).map((t) => (
              <li key={t.slug} className="topic-row last:border-0">
                <Link
                  to={`/topic/${t.slug}`}
                  className="flex items-center justify-between px-5 py-3 group no-underline"
                >
                  <span className="text-sm text-slate-300 group-hover:text-white transition-colors font-medium">
                    {t.name}
                  </span>
                  <div className="flex items-center gap-2">
                    <span className="badge badge-green">✓ done</span>
                    <span className="text-slate-600 group-hover:text-primary transition-colors text-xs">→</span>
                  </div>
                </Link>
              </li>
            ))}
          </ul>
        )}
      </section>

      {/* Quiz history */}
      <section className="glass mb-6 overflow-hidden animate-fade-up-d3">
        <div
          className="flex items-center justify-between px-5 py-3.5"
          style={{ borderBottom: "1px solid rgba(255,255,255,0.06)" }}
        >
          <p className="section-label">Quiz History</p>
          <span className="text-xs font-mono" style={{ color: "#475569" }}>
            {quizScores.length} taken
          </span>
        </div>

        {quizScores.length === 0 ? (
          <div className="px-5 py-8 text-center">
            <p className="text-slate-500 text-sm mb-3">No quizzes taken yet.</p>
            <Link to="/quiz" className="btn-accent text-xs" style={{ padding: "8px 16px", display: "inline-block" }}>
              Take a Quiz →
            </Link>
          </div>
        ) : (
          <ul className="list-none m-0 p-0">
            {[...quizScores].reverse().map((s, i) => {
              const pct = Math.round((s.score / s.total) * 100);
              const scoreColor =
                pct >= 80 ? "#22c55e" : pct >= 50 ? "#f59e0b" : "#ef4444";
              return (
                <li
                  key={i}
                  className="flex items-center justify-between px-5 py-3.5"
                  style={{ borderBottom: "1px solid rgba(255,255,255,0.04)" }}
                >
                  <div>
                    <p className="text-sm text-slate-300 font-medium">{s.topic}</p>
                    <p className="text-xs text-slate-500 mt-0.5">
                      {new Date(s.date).toLocaleDateString("en-IN", {
                        day: "numeric", month: "short", year: "numeric",
                      })}
                    </p>
                  </div>
                  <div className="text-right">
                    <p
                      className="text-sm font-bold font-mono"
                      style={{ color: scoreColor }}
                    >
                      {s.score}/{s.total}
                    </p>
                    <p className="text-xs" style={{ color: scoreColor }}>{pct}%</p>
                  </div>
                </li>
              );
            })}
          </ul>
        )}
      </section>

      {/* Clear button */}
      <button
        onClick={handleClear}
        className="text-xs text-slate-600 hover:text-red-400 transition-colors"
      >
        Clear all progress data
      </button>

      <div className="h-16" />
    </main>
  );
}
